import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { JukeboxStateParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/JukeboxStateParser';

export class JukeboxStateEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, JukeboxStateParser);
    }

    public getParser(): JukeboxStateParser {
        return this.parser as JukeboxStateParser;
    }
}
